INSERT INTO `v1_d209f75f973f81be26650d3364df60224f8959a608c699a134dced73946a32db` VALUES ("だからわたし、\n勇気を出して言ってみたんです！\nお友だちになりませんか、って。", 11, 72, 0, 1, 0, 72021, 1, 1, 10, 0);
