INSERT INTO `v1_d209f75f973f81be26650d3364df60224f8959a608c699a134dced73946a32db` VALUES ("……でも。\n今回の冒険で、夢見ることは\n大きな力だと知りましたから。", 11, 142, 0, 1, 0, 142024, 1, 1, 10, 0);
